class Node:
    def __init__(self, data):
        self.data = data
        self.left = None
        self.right = None

def hasPathSum(node, targetSum):
    if node is None:
        return False

    if node.left is None and node.right is None:
        return node.data == targetSum

    return hasPathSum(node.left, targetSum - node.data) or hasPathSum(node.right, targetSum - node.data)

if __name__ == '__main__':
    root = Node(5)
    root.left = Node(4)
    root.right = Node(8)
    root.left.left = Node(11)
    root.right.left = Node(13)
    root.right.right = Node(4)
    root.left.left.left = Node(7)
    root.left.left.right = Node(2)
    root.right.right.right = Node(1)

    targetSum = 22

    if hasPathSum(root, targetSum):
        print("Path with sum", targetSum, "exists")
    else:
        print("Path with sum", targetSum, "does not exist")

    targetSum = 26
    if hasPathSum(root, targetSum):
        print("Path with sum", targetSum, "exists")
    else:
        print("Path with sum", targetSum, "does not exist")
